<script>
let currentRoute='phaethon',selectedPhaethon='wise',currentPreset='resident',selectedChapter=0,currentMode='story';

function selectMode(mode){currentMode=mode;document.querySelectorAll('#step-mode .route-card').forEach(c=>c.classList.remove('active'));document.querySelector('#step-mode [data-mode="'+mode+'"]').classList.add('active');updateGoal();toggleGoalVisibility()}
function toggleGoalVisibility(){document.getElementById('chapter-goal-section').style.display=(currentRoute==='custom'&&currentMode==='sandbox')?'':'none'}

const CHAPTER_NAMES={0:"序章·法厄同",1:"第一章·远景案",2:"第二章·白祇重工",3:"第三章·维多利亚家政",4:"第四章·外环",5:"第五章·落星风暴",6:"第二季第一章·云岿山",7:"第二季第二章·澄辉坪",8:"第二季第三章·防卫军",9:"第二季第四章·守夜人",10:"第二季第五章·将临深渊",11:"第二季第六章·微光引灯",12:"第二季·间章",13:"第二季·尾音上",14:"第二季·尾音下",15:"第三季第一章·梦游者"};

function onChapterChange(){selectedChapter=parseInt(document.getElementById('startChapter').value)||0;document.getElementById('chapter-hint').textContent=selectedChapter===0?'从序章开始，体验完整剧情':'从「'+CHAPTER_NAMES[selectedChapter]+'」开始冒险';updateGoal()}

const RACE_TRAITS={"人类":"普通人类，无特殊种族特性。适应性最强，新艾利都最普遍的种族。","猫希人":"猫科亚人，敏捷灵活、夜视优异、平衡感极强。隐性猫爪可伸缩。常见职业: 盗洞客、情报贩子。","虎希人":"虎科亚人，力量和爆发力在希人中首屈一指。尾巴会暴露情绪。","犬希人":"犬科亚人，嗅觉极其灵敏，可追踪残留以太气味。治安局同事对你更信赖。","狼希人":"狼科亚人，天然领导气质与群体协作本能。优雅表面下是掠食者基因。","鲨希人":"海洋掠食者亚人，在液态以太（瘴气）中更活跃。牙齿可再生。","熊希人":"熊科亚人，防御力与耐力顶尖。外表凶悍内心敦厚。","鼠希人":"啮齿类亚人，小巧灵活。狭窄空间适应力无人能及。","兔希人":"兔科亚人，跳跃力与听觉超出所有希人。轻微对称强迫症是常见特征。","狐希人":"狐科亚人，天生以太感知力远超其他希人。","章鱼希人":"最罕见希人亚种。触手可回溯物体附着的过去影像——记忆触摸。","羊希人":"羊科亚人，以太感知特异化为守夜人之眼——能精确定位以骸。","熊猫希人":"珍惜亚人种，外表憨厚武力值极高。对美食有执念。","报丧女妖":"传说种族。音波可直接作用于以太物质。被视为不祥之兆。","鬼族":"非人种族，身体耐久数倍于人类，恢复快。有自己的社区和文化。","精灵":"稀有长寿种族，以太适应性天生极高。沉默里装着千年故事。","吸血鬼":"夜行种族，夜间感官与再生显著增强。吸血非生存必须。","智能构造体":"人工制造的智能生命。不需进食/呼吸/睡眠。身体可更换——但核心代码是唯一的。"};
function updateRaceHint(){document.getElementById('race-hint').textContent=RACE_TRAITS[document.getElementById('race').value]||''}

