function startAdventure(){if(adventureStarted)return;if(currentRoute==='custom'){var nv=document.getElementById('name').value.trim();if(!nv){alert("请填写角色姓名！");return}}adventureStarted=true;var btn=document.querySelector('.start-btn');if(btn){btn.disabled=true;btn.textContent='✅ 已开始';btn.style.opacity='0.6';btn.style.cursor='not-allowed'}document.querySelectorAll('input, select, button').forEach(el=>{if(el!==btn)el.disabled=true});document.querySelectorAll('.route-card, .phaethon-card, .preset-btn, .bb-card').forEach(el=>{el.onclick=null;el.style.pointerEvents='none';el.style.opacity='0.6';el.style.cursor='default'});
