if(currentRoute==='phaethon'){var isWise=selectedPhaethon==='wise';var charName=isWise?'哲':'铃';var siblingName=isWise?'铃':'哲';var siblingRelation=isWise?'妹妹':'哥哥';var gear=isWise?PHAETHON_GEAR.wise:PHAETHON_GEAR.belle;var ch=PHAETHON_CHAPTERS[selectedChapter]||PHAETHON_CHAPTERS[0];patches.push({op:"replace",path:"/世界/当前模式",value:currentMode==='sandbox'?"沙盒":"剧情"},{op:"replace",path:"/世界/当前时间",value:ch.time},{op:"replace",path:"/世界/当前地点",value:"六分街·Random Play录像店·一楼客厅"},{op:"replace",path:"/主角/基础/是否为法厄同",value:true},{op:"replace",path:"/主角/基础/姓名",value:charName},{op:"replace",path:"/主角/基础/性别",value:isWise?"男":"女"},{op:"replace",path:"/主角/基础/身份",value:"法厄同·传奇绳匠"},{op:"replace",path:"/主角/基础/金钱",value:ch.money},{op:"replace",path:"/主角/属性/以太适应性",value:100},{op:"replace",path:"/主角/战斗定位",value:"支援"},{op:"replace",path:"/主角/当前情绪",value:"平静/专注"},{op:"replace",path:"/主角/着装/上衣",value:gear.上衣},{op:"replace",path:"/主角/着装/下装",value:gear.下装},{op:"replace",path:"/主角/着装/内衣",value:gear.内衣},{op:"replace",path:"/主角/着装/内裤",value:gear.内裤},{op:"replace",path:"/主角/着装/鞋子",value:gear.鞋子},{op:"replace",path:"/主角/着装/饰品",value:gear.饰品},{op:"replace",path:"/邦布/邦布伙伴",value:"伊埃斯"},{op:"replace",path:"/邦布/拥有的邦布",value:["伊埃斯"]},{op:"replace",path:"/世界/城市流言",value:ch.rumor});patches.push({op:"replace",path:"/世界/章节进度",value:selectedChapter},{op:"replace",path:"/世界/当前章节",value:CHAPTER_NAMES[selectedChapter]||"序章·法厄同"});for(var f in ch.factions){patches.push({op:"replace",path:"/阵营/"+f,value:ch.factions[f]})}var rs=selectedChapter<=0?0:Math.round((0.2+(selectedChapter-1)/14*0.8)*100)/100;function addNpcs(npcs){npcs.forEach(npc=>{var d=JSON.parse(JSON.stringify(npc.data));if(d.关系){if(d.关系.好感度)d.关系.好感度=Math.round(d.关系.好感度*rs);if(d.关系.信任度)d.关系.信任度=Math.round(d.关系.信任度*rs)}patches.push({op:"add",path:"/NPCs/"+npc.name,value:d})})}if(selectedChapter>=1)addNpcs(HARE_NPCS);if(selectedChapter>=5)addNpcs(NEPS_NPCS);narrative=ch.narrative}else{var name=document.getElementById('name').value.trim()||'(未命名)';var race=document.getElementById('race').value;var gender=document.getElementById('gender').value;var age=parseInt(document.getElementById('age').value)||25;var bio=document.getElementById('bio').value;var ether=parseInt(document.getElementById('ether').value)||50;var combat=document.getElementById('combat').value;var faction=document.getElementById('faction').value;var special=document.getElementById('special').value||'无';var gv=(PRESET_GEAR[currentPreset]||PRESET_GEAR.resident);var g=(gender==='女'?gv.female:gv.male);var combatRole=currentPreset==='officer'?'执法者':currentPreset==='raider'||currentPreset==='rider'?'游荡者':currentPreset==='proxy'?'绳匠':currentPreset==='hia'?'调查员':'平民';var locS=document.getElementById('startLocation');var location=PRESETS[currentPreset].canPickLocation?(locS?locS.value:PRESETS[currentPreset].location):PRESETS[currentPreset].location;patches.push({op:"replace",path:"/世界/当前模式",value:currentMode==='sandbox'?"沙盒":"剧情"},{op:"replace",path:"/世界/当前时间",value:"新艾利都历·上午 08:00"},{op:"replace",path:"/世界/当前地点",value:location},{op:"replace",path:"/主角/基础/是否为法厄同",value:false},{op:"replace",path:"/主角/基础/姓名",value:name},{op:"replace",path:"/主角/基础/性别",value:gender},{op:"replace",path:"/主角/基础/年龄",value:age+"岁"},{op:"replace",path:"/主角/基础/身份",value:bio},{op:"replace",path:"/主角/基础/金钱",value:10000},{op:"replace",path:"/主角/属性/种族",value:race},{op:"replace",path:"/主角/属性/以太适应性",value:ether},{op:"replace",path:"/主角/属性/战斗能力",value:combat},{op:"replace",path:"/主角/基础/所属势力",value:faction},{op:"replace",path:"/主角/属性/特殊能力",value:special},{op:"replace",path:"/主角/战斗定位",value:combatRole},{op:"replace",path:"/主角/当前情绪",value:"平静"},{op:"replace",path:"/主角/着装/上衣",value:g.上衣},{op:"replace",path:"/主角/着装/下装",value:g.下装},{op:"replace",path:"/主角/着装/内衣",value:g.内衣},{op:"replace",path:"/主角/着装/内裤",value:g.内裤},{op:"replace",path:"/主角/着装/鞋子",value:g.鞋子},{op:"replace",path:"/主角/着装/饰品",value:g.饰品},{op:"replace",path:"/邦布/邦布伙伴",value:selectedBangboo},{op:"replace",path:"/邦布/拥有的邦布",value:[selectedBangboo]},{op:"replace",path:"/世界/城市流言",value:pickRandomRumor()});patches.push({op:"replace",path:"/世界/章节进度",value:selectedChapter},{op:"replace",path:"/世界/当前章节",value:CHAPTER_NAMES[selectedChapter]||"序章·法厄同"});if(currentPreset==='officer'){patches.push({op:"replace",path:"/阵营/治安局",value:50});NEPS_NPCS.forEach(npc=>patches.push({op:"add",path:"/NPCs/"+npc.name,value:npc.data}))}var pgoals=PRESET_GOALS[currentPreset];var sandboxGoal=pgoals?(pgoals[selectedChapter]||pgoals['default']):'';if(currentMode==='sandbox'){narrative=(LOCATION_NARRATIVES[location]||LOCATION_NARRATIVES['六分街·公寓'])+'\n\n你是${name}——${bio}。'+'🎯 当前目标：${sandboxGoal}'}else{narrative=(LOCATION_NARRATIVES[location]||LOCATION_NARRATIVES['六分街·公寓'])+'\n\n你是${name}——${bio}。'+'📖 剧情模式——法厄同的故事正在展开。'}}
var ps=JSON.stringify(patches);var uv='<Up'+'dateVariable>';var ue='</Up'+'dateVariable>';var fp='/send ${narrative}\n\n<span style="display:none;">\n${uv}\n<JSONPatch>\n${ps}\n</JSONPatch>\n${ue}\n</span>|/trigger';if(typeof triggerSlash==='function'){triggerSlash(fp)}else{alert("无法自动发送。请复制以下文本手动发送：\n\n"+narrative)}}

selectPreset('resident');renderBangbooCards();updateGoal();updateRaceHint();
</script>
</body>
</html>
